* {
	box-sizing: border-box;
}

html,
body {
	margin: 0;
	width: 100%;
	min-height: 100%;
	font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
		"Segoe UI", sans-serif;
	color: var(--text);
	background: #090b10;
}

body {
	min-height: 100vh;
	display: flex;
	align-items: center;
	justify-content: center;
	padding: 24px;
	position: relative;
	overflow: hidden;
	isolation: isolate;
}

body::before {
	content: "";
	position: fixed;
	inset: 0;
	z-index: -2;
	background-image: url("https://img.freepik.com/free-vector/robots-pattern-design_1131-2.jpg");
	background-repeat: repeat;
	background-size: 320px 320px;
	background-position: 0 0;
	animation: bgDrift 36s linear infinite;
	transform: scale(1.08);
	opacity: 0.74;
}

body::after {
	content: "";
	position: fixed;
	inset: 0;
	z-index: -1;
	background: radial-gradient(
			circle at top,
			rgba(255, 255, 255, 0.06),
			transparent 32%
		),
		rgba(8, 10, 14, 0.72);
	pointer-events: none;
}

@keyframes bgDrift {
	from {
		background-position: 0 0;
	}
	to {
		background-position: 320px 320px;
	}
}

.shell {
	width: min(100%, 460px);
}

.logo {
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 12px;
	margin: 0 0 18px;
	padding: 10px 18px;
	border-radius: 999px;
	background: rgba(255, 255, 255, 0.04);
	border: 1px solid rgba(255, 255, 255, 0.08);
	box-shadow: 0 12px 30px rgba(0, 0, 0, 0.22);
	backdrop-filter: blur(10px);
	width: fit-content;
	margin-inline: auto;
}

.logo-icons {
	font-size: 1.45rem;
	line-height: 1;
	letter-spacing: 0.08em;
	filter: drop-shadow(0 4px 10px rgba(255, 255, 255, 0.08));
}

.logo-text {
	font-size: clamp(1.55rem, 4vw, 2.15rem);
	font-weight: 800;
	letter-spacing: 0.02em;
	background: linear-gradient(180deg, #ffffff 0%, #cfd6e6 100%);
	-webkit-background-clip: text;
	background-clip: text;
	color: transparent;
	text-shadow: 0 8px 24px rgba(255, 255, 255, 0.08);
}

.card {
	background: var(--panel);
	border: 1px solid var(--line);
	border-radius: 24px;
	padding: 22px;
	box-shadow: var(--shadow);
	backdrop-filter: blur(14px);
}

.captcha-row {
	width: 100%;
	display: flex;
	align-items: center;
	gap: 14px;
	padding: 16px;
	border-radius: 18px;
	border: 1px solid var(--line);
	background: rgba(255, 255, 255, 0.03);
	cursor: pointer;
	transition: transform 0.16s ease, border-color 0.16s ease;
}

.captcha-row:hover {
	transform: translateY(-1px);
	border-color: rgba(255, 255, 255, 0.18);
}

.check {
	width: 28px;
	height: 28px;
	border-radius: 8px;
	border: 2px solid rgba(255, 255, 255, 0.32);
	display: grid;
	place-items: center;
	flex: 0 0 auto;
	font-size: 15px;
	line-height: 1;
	transition: 0.2s ease;
}

.captcha-row.checked .check {
	border-color: var(--good);
	background: rgba(159, 244, 179, 0.12);
	color: var(--good);
}

.captcha-label {
	font-size: 1rem;
	font-weight: 600;
	flex: 1;
	text-align: left;
	color: #ffffff;
}

.register-btn {
	width: 100%;
	margin-top: 14px;
	border: 0;
	border-radius: 16px;
	padding: 14px 18px;
	font: inherit;
	font-weight: 700;
	background: #ffffff;
	color: #0a0c11;
	cursor: pointer;
	transition: transform 0.16s ease, opacity 0.16s ease;
}

.register-btn:hover {
	transform: translateY(-1px);
}

.register-btn:disabled {
	cursor: not-allowed;
	opacity: 0.45;
	transform: none;
}

.message {
	min-height: 24px;
	margin-top: 14px;
	text-align: center;
	color: var(--muted);
	line-height: 1.4;
	font-size: 0.95rem;
}

.message.bad {
	color: var(--bad);
}

.overlay {
	position: fixed;
	inset: 0;
	display: none;
	align-items: center;
	justify-content: center;
	padding: 20px;
	background: rgba(2, 4, 8, 0.74);
	z-index: 50;
}

.overlay.open {
	display: flex;
}

.modal {
	width: min(100%, 470px);
	background: #111621;
	border: 1px solid var(--line);
	border-radius: 24px;
	padding: 18px;
	box-shadow: var(--shadow);
}

.modal-top {
	display: flex;
	justify-content: space-between;
	gap: 16px;
	align-items: flex-start;
	margin-bottom: 14px;
}

.modal-title {
	margin: 0;
	font-size: 1.02rem;
	font-weight: 800;
}

.modal-subtitle {
	margin: 6px 0 0;
	color: var(--muted);
	font-size: 0.92rem;
	line-height: 1.35;
}

.close-btn {
	border: 0;
	background: transparent;
	color: var(--muted);
	font-size: 1.45rem;
	line-height: 1;
	cursor: pointer;
	padding: 0;
}

.grid {
	display: grid;
	grid-template-columns: repeat(3, 1fr);
	gap: 8px;
	margin-top: 10px;
}

.tile {
	position: relative;
	aspect-ratio: 1 / 1;
	border: 2px solid rgba(255, 255, 255, 0.08);
	border-radius: 14px;
	padding: 0;
	overflow: hidden;
	cursor: pointer;
	background: #172030;
	transition: transform 0.14s ease, border-color 0.14s ease;
}

.tile:hover {
	transform: translateY(-1px);
	border-color: rgba(255, 255, 255, 0.18);
}

.tile.selected {
	border-color: #ffffff;
}

.tile::before {
	content: "";
	position: absolute;
	inset: 0;
	background-image: var(--captcha-image);
	background-size: 300% 300%;
	background-position: var(--x) var(--y);
	filter: saturate(1.02) contrast(1.01);
}

.tile::after {
	content: "";
	position: absolute;
	inset: 0;
	background: rgba(255, 255, 255, 0);
	transition: background 0.14s ease;
}

.tile.selected::after {
	background: rgba(255, 255, 255, 0.16);
	box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.14);
}

.tile:nth-child(1) {
	--x: 0%;
	--y: 0%;
}
.tile:nth-child(2) {
	--x: 50%;
	--y: 0%;
}
.tile:nth-child(3) {
	--x: 100%;
	--y: 0%;
}
.tile:nth-child(4) {
	--x: 0%;
	--y: 50%;
}
.tile:nth-child(5) {
	--x: 50%;
	--y: 50%;
}
.tile:nth-child(6) {
	--x: 100%;
	--y: 50%;
}
.tile:nth-child(7) {
	--x: 0%;
	--y: 100%;
}
.tile:nth-child(8) {
	--x: 50%;
	--y: 100%;
}
.tile:nth-child(9) {
	--x: 100%;
	--y: 100%;
}

.modal-actions {
	display: flex;
	gap: 10px;
	margin-top: 14px;
}

.btn {
	flex: 1;
	border: 0;
	border-radius: 14px;
	padding: 13px 14px;
	font: inherit;
	font-weight: 700;
	cursor: pointer;
	transition: transform 0.16s ease;
}

.btn:hover {
	transform: translateY(-1px);
}

.btn.secondary {
	background: rgba(255, 255, 255, 0.08);
	color: var(--text);
	border: 1px solid rgba(255, 255, 255, 0.1);
}

.btn.primary {
	background: #ffffff;
	color: #0a0c11;
}

@media (max-width: 480px) {
	.card,
	.modal {
		border-radius: 20px;
	}

	.logo {
		gap: 10px;
		padding: 10px 14px;
	}

	.logo-icons {
		font-size: 1.2rem;
	}

	body::before {
		background-size: 260px 260px;
	}

	@keyframes bgDrift {
		from {
			background-position: 0 0;
		}
		to {
			background-position: 260px 260px;
		}
	}
}
